import React from 'react';
import { User, Smartphone, History, LogOut, Bell, Shield, ChevronRight } from 'lucide-react';
import { useCurrency } from '../context/CurrencyContext';

export default function ProfileScreen({ onLogout, onHistory }) {
  const { currency, setCurrency } = useCurrency(); // use context

  const menuItems = [
    { icon: User, label: 'Personal Information', color: 'bg-emerald-50 text-emerald-600' },
    { icon: Bell, label: 'Notifications', color: 'bg-blue-50 text-blue-600' },
    { icon: Shield, label: 'Security & Privacy', color: 'bg-purple-50 text-purple-600' },
    { icon: Smartphone, label: 'Linked Devices', color: 'bg-orange-50 text-orange-600' },
    { icon: History, label: 'Transactions History', color: 'bg-gray-100 text-gray-600', action: onHistory },
  ];

  const handleCurrencyChange = (e) => {
    const selected = e.target.value;
    setCurrency(selected); // update context
    localStorage.setItem('appCurrency', selected); // persist selection
  };

  return (
    <div className="p-6 pb-24 animate-in fade-in duration-300">
      {/* Avatar and User Info */}
      <div className="flex flex-col items-center mb-10 pt-8">
        <div className="relative">
          <div className="w-28 h-28 bg-emerald-50 rounded-full flex items-center justify-center text-5xl border-4 border-white shadow-xl">
            👤
          </div>
          <div className="absolute bottom-1 right-1 w-8 h-8 bg-[#00875A] rounded-full border-4 border-white flex items-center justify-center">
            <div className="w-2 h-2 bg-white rounded-full"></div>
          </div>
        </div>
        <h2 className="text-2xl font-black text-gray-900 mt-4">Faith Bode</h2>
        <p className="text-gray-400 text-sm font-bold uppercase tracking-widest mt-1">Nest Premium</p>
      </div>

      {/* Menu Items */}
      <div className="space-y-3">
        {menuItems.map((item, idx) => (
          <button 
            key={idx}
            onClick={item.action}
            className="w-full flex items-center justify-between p-4 bg-white rounded-2xl border border-gray-50 active:bg-gray-50 transition-all group"
          >
            <div className="flex items-center gap-4">
              <div className={`w-11 h-11 rounded-xl flex items-center justify-center ${item.color}`}>
                <item.icon className="w-5 h-5" />
              </div>
              <span className="font-bold text-gray-700">{item.label}</span>
            </div>
            <ChevronRight className="w-5 h-5 text-gray-300 group-hover:translate-x-1 transition-transform" />
          </button>
        ))}

        {/* Currency Selector */}
        <div className="w-full flex items-center justify-between p-4 bg-white rounded-2xl border border-gray-50 mt-3">
          <span className="font-bold text-gray-700">App Currency</span>
          <select
            className="p-2 rounded-xl bg-gray-50 border border-gray-100 outline-none focus:border-[#00875A]"
            value={currency} // bind to context
            onChange={handleCurrencyChange}
          >
            <option value="USD">$ - USD</option>
            <option value="NGN">₦ - NGN</option>
            <option value="EUR">€ - EUR</option>
          </select>
        </div>

        {/* Sign Out */}
        <button 
          onClick={onLogout}
          className="w-full flex items-center justify-between p-4 bg-red-50/50 rounded-2xl border border-red-50 text-red-500 mt-6 active:bg-red-50"
        >
          <div className="flex items-center gap-4">
            <div className="w-11 h-11 rounded-xl flex items-center justify-center bg-red-100">
              <LogOut className="w-5 h-5" />
            </div>
            <span className="font-black">Sign Out</span>
          </div>
        </button>
      </div>
    </div>
  );
}
